public class InterThreadCommunicationExample {
    public static void main(String[] args) {
        SharedResource resource = new SharedResource();

        // Producer thread
        Thread producer = new Thread(() -> {
            for (int i = 1; i <= 5; i++) {
                resource.produce(i);
                try {
                    Thread.sleep(1000);  // Simulate production time
                } catch (InterruptedException e) {
                    e.printStackTrace();
                }
            }
        });

        // Consumer thread
        Thread consumer = new Thread(() -> {
            for (int i = 1; i <= 5; i++) {
                resource.consume();
                try {
                    Thread.sleep(1500);  // Simulate consumption time
                } catch (InterruptedException e) {
                    e.printStackTrace();
                }
            }
        });

        producer.start();
        consumer.start();

        try {
            producer.join();
            consumer.join();
        } catch (InterruptedException e) {
            e.printStackTrace();
        }

        System.out.println("Producer-consumer complete!");
    }
}

class SharedResource {
    private int data;
    private boolean available = false;

    // Producer
    synchronized void produce(int value) {
        while (available) {
            try {
                wait();  // Wait for consumer to consume
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }

        data = value;
        available = true;
        System.out.println("Produced: " + data);
        notify();  // Notify consumer
    }

    // Consumer
    synchronized void consume() {
        while (!available) {
            try {
                wait();  // Wait for producer to produce
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }

        System.out.println("Consumed: " + data);
        available = false;
        notify();  // Notify producer
    }
}

// Alternative: Using wait/notify with multiple producers/consumers
class SharedQueue {
    private final java.util.LinkedList<Integer> queue = new java.util.LinkedList<>();
    private final int CAPACITY = 3;

    synchronized void produce(int value) throws InterruptedException {
        while (queue.size() == CAPACITY) {
            System.out.println("Queue full, producer waiting...");
            wait();
        }

        queue.add(value);
        System.out.println("Produced: " + value + ", Queue: " + queue);
        notifyAll();  // Notify all waiting threads
    }

    synchronized int consume() throws InterruptedException {
        while (queue.isEmpty()) {
            System.out.println("Queue empty, consumer waiting...");
            wait();
        }

        int value = queue.removeFirst();
        System.out.println("Consumed: " + value + ", Queue: " + queue);
        notifyAll();  // Notify all waiting threads
        return value;
    }
}

